 47	void SGSidentityReq(void *msg, nr_user_nas_t *UE) {
 48	  Identityrequest_t *idmsg=(Identityrequest_t *) msg;
 49	
 50	  if (idmsg->it == SUCI ) {
 51	    LOG_I(NAS,"Received Identity request, scheduling answer\n");
