 61	void UEprocessNAS(void *msg,nr_user_nas_t *UE) {
 62	  SGScommonHeader_t *header=(SGScommonHeader_t *) msg;
 63	
 64	  if ( header->sh > 4 )
 65	    SGSabortNet(msg, UE);
 66	  else {
 67	    switch  (header->epd) {
 68	      case SGSmobilitymanagementmessages:
 69	        LOG_I(NAS,"Received message: %s\n", idStr(message_text_info, header->mt));
 70	
 71	        switch (header->mt) {
 72	          case Authenticationrequest:
 73	            SGSauthenticationReq(msg, UE);
 74	            break;
 75	
 76	          case Identityrequest:
 77	            SGSidentityReq(msg, UE);
 78	            break;
 79	
 80	          case Securitymodecommand:
 81	            SGSsecurityModeCommand(msg, UE);
 82	            break;
 83	
 84	          default:
 85	            SGSabortNet(msg, UE);
 86	        }
 87	
 88	        break;
 89	
 90	      case SGSsessionmanagementmessages:
 91	        SGSabortNet(msg, UE);
 92	        break;
 93	
 94	      default:
 95	        SGSabortNet(msg, UE);
 96	    }
 97	  }
 98	}
